 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	import { useNavigate } from 'react-router-dom-v5-compat';
 4	
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import {
 7	  Button,
 8	  ButtonVariant,
 9	  EmptyState,
10	  EmptyStateActions,
11	  EmptyStateBody,
12	  EmptyStateFooter,
13	  EmptyStateHeader,
14	  EmptyStateIcon,
15	  EmptyStateVariant,
16	} from '@patternfly/react-core';
17	import { RocketIcon, VirtualMachineIcon } from '@patternfly/react-icons';
18	
19	type VirtualMachineInstanceEmptyStateProps = {
20	  catalogURL: string;
21	};
22	const VirtualMachineInstanceEmptyState: FC<VirtualMachineInstanceEmptyStateProps> = ({
23	  catalogURL,
24	}) => {
25	  const { t } = useKubevirtTranslation();
26	  const navigate = useNavigate();
27	
28	  return (
29	    <EmptyState variant={EmptyStateVariant.lg}>
30	      <EmptyStateHeader
31	        headingLevel="h4"
32	        icon={<EmptyStateIcon icon={VirtualMachineIcon} />}
33	        titleText={<>{t('No VirtualMachinesInstances found')}</>}
34	      />
35	      <EmptyStateBody>
36	        <Trans ns="plugin__kubevirt-plugin" t={t}>
37	          See the{' '}
38	          <Button isInline onClick={() => navigate(catalogURL)} variant={ButtonVariant.link}>
39	            catalog tab
40	          </Button>{' '}
41	          to quickly create a VirtualMachine from the available Templates.
42	        </Trans>
43	      </EmptyStateBody>
44	      <EmptyStateFooter>
45	        <EmptyStateActions>
46	          <Button onClick={() => navigate(catalogURL)} variant={ButtonVariant.primary}>
47	            {t('Create VirtualMachine')}
48	          </Button>
49	        </EmptyStateActions>
50	        <EmptyStateActions>
51	          <Button
52	            onClick={() =>
53	              navigate({ pathname: '/quickstart', search: '?keyword=virtual+machine' })
54	            }
55	            icon={<RocketIcon />}
56	            variant={ButtonVariant.secondary}
57	          >
58	            {t('Learn how to use VirtualMachines')}
59	          </Button>
60	        </EmptyStateActions>
61	      </EmptyStateFooter>
62	    </EmptyState>
63	  );
64	};
65	
66	export default VirtualMachineInstanceEmptyState;

